/* Layout 1: Dashboard com áreas (mobile-first) */

.dashboard {
  display: grid;
  grid-template-columns: 1fr;
  grid-template-areas:
    "header"
    "sidebar"
    "main";
  gap: 16px;
  align-items: start;
}

.d-header { grid-area: header; }
.d-sidebar { grid-area: sidebar; }
.d-main { grid-area: main; }

@media (min-width: 1024px) {
  .dashboard {
    grid-template-columns: 280px 1fr;
    grid-template-areas:
      "header header"
      "sidebar main";
  }
}

/* Layout 2: Cards responsivos (auto-fit + minmax) */

.cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 16px;
}

/* Layout 3: Article + Aside */

.article-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 24px;
  align-items: start;
}

@media (min-width: 1024px) {
  .article-layout {
    grid-template-columns: 1fr 320px;
  }
}

/* Container pro */
.container {
  max-width: 1100px;
  margin: 0 auto;
  padding: 16px;
}

@media (min-width: 768px) {
  .container { padding: 24px; }
}

@media (min-width: 1024px) {
  .container { padding: 32px; }
}
